SET @row_num = 0;
SET @cur_stage = '';

UPDATE lifecycle_services ls
JOIN (
  SELECT id,
    @row_num := IF(@cur_stage = stageCode, @row_num + 10, 10) AS new_sort,
    @cur_stage := stageCode AS cur_stage_val
  FROM lifecycle_services
  ORDER BY stageCode, sortOrder, id
) ranked ON ls.id = ranked.id
SET ls.sortOrder = ranked.new_sort;

